34	template<typename T>
35	void multi_gpu_gpt_example(const INIReader reader, std::string in_csv);
36	
37	int main(int argc, char* argv[])
38	{
39	    mpi::initialize(&argc, &argv);
40	    srand(0);
41	
42	    std::string ini_name;
43	    if (argc >= 2) {
44	        ini_name = std::string(argv[1]);
45	    }
46	    else {
47	        ini_name = "../examples/cpp/multi_gpu_gpt/gpt_config.ini";
48	    }
49	
50	    std::string in_csv;
51	    if (argc == 3) {
52	        in_csv = std::string(argv[2]);
53	    }
54	    else {
55	        in_csv = "../examples/cpp/multi_gpu_gpt/start_ids.csv";
56	    }
57	
58	    INIReader reader = INIReader(ini_name);
59	    if (reader.ParseError() < 0) {
60	        std::cout << "[ERROR] Can't load '" << ini_name << "'\n";
61	        return -1;
62	    }
63	    const std::string data_type = reader.Get("ft_instance_hyperparameter", "data_type");
64	
65	    if (data_type == "fp32") {
66	        multi_gpu_gpt_example<float>(reader, in_csv);
67	    }
68	    else if (data_type == "fp16") {
69	        multi_gpu_gpt_example<half>(reader, in_csv);
70	    }
71	#ifdef ENABLE_BF16
72	    else if (data_type == "bf16") {
73	        multi_gpu_gpt_example<__nv_bfloat16>(reader, in_csv);
74	    }
75	#endif
76	    else {
77	        printf("[ERROR] data_type should be fp32, fp16 or bf16 ! \n");
78	        return -1;
79	    }
80	    mpi::finalize();
81	    return 0;
82	}
83	
84	template<typename T>
85	void multi_gpu_gpt_example(const INIReader reader, std::string in_csv)
86	{
87	    const DataType data_type = getTensorType<T>();
88	
89	    auto                                       model_config = read_model_config(reader);
90	    std::map<std::string, std::pair<int, int>> p_prompt_tuning_table_pair(init_prompt_tuning_map(reader, model_config));
91	    auto                                       request_config = read_request_config(reader);
92	
93	    NcclParam tensor_para, pipeline_para;
94	    int       rank, world_size;
95	    std::tie(rank, world_size) = init_multiprocessing(model_config);
96	
97	    cudaStream_t                   stream;
98	    cudaDeviceProp                 prop;
99	    Allocator<AllocatorType::CUDA> allocator(init_cuda_ctx(stream, prop, rank));
100	
101	    cublasHandle_t   cublas_handle;
102	    cublasLtHandle_t cublaslt_handle;
103	    std::mutex       cublas_wrapper_mutex;
104	    cublasAlgoMap    cublas_algo_map;
105	
106	#ifdef SPARSITY_ENABLED
107	    cusparseLtHandle_t cusparselt_handle;
108	#endif
109	
110	    init_nccl(model_config, tensor_para, pipeline_para);
111	    cublasMMWrapper cublas_wrapper = init_cublas_ctx(data_type,
112	                                                     stream,
113	                                                     allocator,
114	                                                     cublas_handle,
115	                                                     cublas_wrapper_mutex,
116	                                                     cublaslt_handle,
117	                                                     cublas_algo_map
118	#ifdef SPARSITY_ENABLED
119	                                                     ,
120	                                                     cusparselt_handle
121	#endif
122	    );
123	
124	    ParallelGptWeight<T> gpt_weights(model_config.hidden_units,
125	                                     model_config.inter_size,
126	                                     model_config.vocab_size,
127	                                     model_config.decoder_layers,
128	                                     model_config.max_seq_len,
129	                                     tensor_para.world_size_,
130	                                     tensor_para.rank_,
131	                                     pipeline_para.world_size_,
132	                                     pipeline_para.rank_,
133	                                     model_config.int8_mode,
134	                                     model_config.prompt_learning_type,
135	                                     p_prompt_tuning_table_pair,
136	                                     model_config.gpt_variants);
137	    gpt_weights.loadModel(model_config.model_dir);
138	#ifdef SPARSITY_ENABLED
139	    if (model_config.sparse) {
140	        printf("[INFO] Compress weights for sparse inference\n");
141	        gpt_weights.compress_weights(cublas_wrapper);
142	    }
143	#endif
144	
145	    unsigned long long random_seed;
146	    if (rank == 0) {
147	        random_seed = (unsigned long long)(0);
148	    }
149	    if (world_size > 1) {
150	        mpi::bcast(&random_seed, 1, mpi::MPI_TYPE_UNSIGNED_LONG_LONG, 0, mpi::COMM_WORLD);
151	    }
152	
153	    AttentionType attention_type = getAttentionType<T>(model_config.size_per_head,
154	                                                       getSMVersion(),
155	                                                       request_config.remove_padding,  // remove_padding
156	                                                       0,                            // gpt supports any-seq-length fmha
157	                                                       model_config.int8_mode != 2,  // is_fuse
158	                                                       false,                        // with_relative_position_bias
159	                                                       true);                        // causal_mask
160	
161	    ParallelGpt<T> gpt = ParallelGpt<T>(0,  // max_batch_size, FT will adjust the buffer automatically.
162	                                        0,  // max_seq_len, FT will adjust the buffer automatically.
163	                                        0,  // max_input_len, FT will adjust the buffer automatically.
164	                                        0,  // beam_width, FT will adjust the buffer automatically.
165	                                        model_config.head_num,
166	                                        model_config.size_per_head,
167	                                        model_config.inter_size,
168	                                        model_config.decoder_layers,
169	                                        0,   // expert_num
170	                                        0,   // moe_k
171	                                        {},  // moe_layer_index
172	                                        model_config.vocab_size,
173	                                        model_config.start_id,
174	                                        model_config.end_id,
175	                                        // p/prompt tuning virtual token start id
176	                                        model_config.prompt_learning_start_id,
177	                                        model_config.prompt_learning_type,
178	                                        model_config.gpt_variants,
179	                                        0.0f,  // beam_search_diversity_rate,
180	                                        0,     // top_k,
181	                                        0.0,   // top_p,
182	                                        0,     // random_seed,
183	                                        1.0f,  // temperature,
184	                                        0.0f,  // len_penalty,
185	                                        1.0f,  // repetition_penalty,
186	                                        tensor_para,
187	                                        pipeline_para,
188	                                        stream,
189	                                        &cublas_wrapper,
190	                                        &allocator,
191	                                        false,
192	                                        &prop,
193	                                        attention_type,
194	                                        model_config.sparse,
195	                                        model_config.int8_mode,
196	                                        nullptr,
197	                                        0,
198	                                        request_config.shared_contexts_ratio);
199	
200	    std::unordered_map<std::string, Tensor> input_tensors;
201	    int*                                    d_input_ids     = nullptr;
202	    int*                                    d_input_lengths = nullptr;
203	    std::vector<int>                        v_start_lengths;
204	    std::vector<int>                        output_seq_len;
205	    std::vector<int>                        p_prompt_tuning_task_ids;
206	
207	    std::unordered_map<std::string, Tensor> output_tensors;
208	    int*                                    d_output_ids                = nullptr;
209	    int*                                    d_sequence_lengths          = nullptr;
210	    float*                                  d_output_log_probs          = nullptr;
211	    float*                                  d_cum_log_probs             = nullptr;
212	    float*                                  d_output_context_embeddings = nullptr;
213	    populate_request(input_tensors,
214	                     output_tensors,
215	                     d_input_ids,
216	                     d_input_lengths,
217	                     v_start_lengths,
218	                     output_seq_len,
219	                     p_prompt_tuning_task_ids,
220	                     d_output_ids,
221	                     d_sequence_lengths,
222	                     d_output_log_probs,
223	                     d_cum_log_probs,
224	                     d_output_context_embeddings,
225	                     random_seed,
226	                     in_csv,
227	                     model_config,
228	                     request_config);
229	    print_mem_usage();
230	
231	    int ite = 1;
232	    cudaDeviceSynchronize();
233	    mpi::barrier();
234	
235	    cudaProfilerStart();
236	    // warm up
237	    ite = 1;
238	
239	    ft_nvtx::setScope("warmup_time");
240	    PUSH_RANGE("warmup time")
241	    for (int i = 0; i < ite; ++i) {
242	        gpt.forward(&output_tensors, &input_tensors, &gpt_weights);
243	    }
244	    cudaDeviceSynchronize();
245	    mpi::barrier();
246	
247	    POP_RANGE;
248	    ft_nvtx::resetScope();
249	
250	    if (rank == 0) {
251	        write_output_tensors(output_tensors);
252	    }
253	    // test time
254	    struct timeval start, end;
255	    mpi::barrier();
256	    cudaDeviceSynchronize();
257	    gettimeofday(&start, NULL);
258	
259	    ite = 10;
260	
261	    for (int i = 0; i < ite; ++i) {
262	        PUSH_RANGE("batch");
263	        gpt.forward(&output_tensors, &input_tensors, &gpt_weights);
264	        POP_RANGE;
265	    }
266	
267	    cudaDeviceSynchronize();
268	    mpi::barrier();
269	
270	    gettimeofday(&end, NULL);
271	
272	    cudaProfilerStop();
273	
274	    const auto total_output_len = output_tensors.at("output_ids").shape[2];
275	    printf("[INFO] request_batch_size %ld beam_width %ld head_num %ld size_per_head %ld total_output_len %ld"
276	           " decoder_layers %ld vocab_size %ld FT-CPP-decoding-beamsearch-time %.2f ms\n",
277	           request_config.request_batch_size,
278	           request_config.beam_width,
279	           model_config.head_num,
280	           model_config.size_per_head,
281	           total_output_len,
282	           model_config.decoder_layers,
283	           model_config.vocab_size,
284	           ((end.tv_sec - start.tv_sec) * 1000 + (end.tv_usec - start.tv_usec) * 0.001) / ite);
285	
286	    safe_free(d_input_ids);
287	    safe_free(d_input_lengths);
288	    safe_free(d_output_ids);
289	    safe_free(d_sequence_lengths);
290	    safe_free(d_output_log_probs);
291	    safe_free(d_cum_log_probs);
292	    safe_free(d_output_context_embeddings);
293	
294	    ftNcclParamDestroy(tensor_para);
295	    ftNcclParamDestroy(pipeline_para);
296	
297	#ifdef SPARSITY_ENABLED
298	    cusparseLtDestroy(&cusparselt_handle);
299	#endif
300	}
301

